import aside from '@/components/shared/aside/aside';
import nav from '@/components/shared/nav/nav';
import { ComponentModule, render } from '@/main';
import { Cliente, ClienteMetaData } from '@/models/cliente';
import { TOAST_TRIGGER } from '@/models/events';
import { EmptyMec, Mec } from '@/models/mec';
import { WorkOrder } from '@/models/or';
import { ToastError } from '@/models/toast';
import { url } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';
import { Modal } from 'flowbite';

const MIN_SEARCH_LENGTH = 2;

export default {
    name: () => 'workOrderNew',
    template: () => import('./work-order-new.html?raw'),
    data: () => ({
        user: getAuthenticatedUser(),
        nav: null as string | null,
        aside: null as string | null,

        userMec: EmptyMec,

        // campos formulario
        cliente: '',
        fecdoc: '',

        newWorkOrder: null as WorkOrder | null,
        workOrderCliente: null as Cliente | null,

        // cliente modal búsqueda
        modalSearchCliente: null as Modal | null,

        // estados de modal búsqueda
        hasSearched: false,
        loadingClientes: false,

        // cliente seleccionado modal búsqueda
        selectedCliente: null as Cliente | null,

        // filtros modal búsqueda
        currentCliente: '',
        currentRaz: '',
        currentNom: '',
        currentCif: '',
        currentDir: '',

        // resultados modal búsqueda
        clientes: [] as Cliente[],
        clienteMetaData: null as ClienteMetaData | null,

        // paginación modal búsqueda
        currentPage: 1,
        pageInfo: '',

        loading: true,
        submitting: false,

        async init() {
            console.log('work-order-new@init');

            this.initModalSearchCliente();

            this.nav = await render(nav);
            this.aside = await render(aside);

            this.loading = false;

            await this.loadUserMec();

            const watchFields = ['currentCliente', 'currentRaz', 'currentNom', 'currentCif', 'currentDir'];
            watchFields.forEach((field) => {
                this.$watch(field, () => {
                    if (!this.hasSearched) {
                        this.hasSearched = true;
                    }
                    if (this.currentPage !== 1) {
                        this.currentPage = 1;
                    }
                    if (
                        this.currentCliente.length < 1 &&
                        this.currentRaz.length < MIN_SEARCH_LENGTH &&
                        this.currentNom.length < MIN_SEARCH_LENGTH &&
                        this.currentCif.length < MIN_SEARCH_LENGTH &&
                        this.currentDir.length < MIN_SEARCH_LENGTH
                    ) {
                        this.resetValues();
                    }
                });
            });
        },

        initModalSearchCliente() {
            this.modalSearchCliente = new Modal(
                this.$refs.modalSearchCliente,
                {
                    placement: 'bottom-right',
                    backdrop: 'static', // Prevent closing the client search modal when clicking outside
                    backdropClasses: 'bg-gray-900/50 dark:bg-gray-900/80 fixed inset-0 z-40',
                    closable: true,
                    onHide: () => {
                        console.log('modal is hidden');
                        this.resetValues();
                        // Reiniciamos los valores de los campos de búsqueda al cerrar el modal
                        [this.currentCliente, this.currentRaz, this.currentNom, this.currentCif, this.currentDir] = [
                            '',
                            '',
                            '',
                            '',
                            '',
                        ];
                    },
                    onShow: () => {
                        console.log('modal is shown');
                    },
                    onToggle: () => {
                        console.log('modal is toggled');
                    },
                },
                {
                    id: 'modal-search-cliente',
                    override: true,
                },
            );
        },

        async loadUserMec() {
            try {
                const r = await fetch(url(`/isiWeb/web/v1/empresas/01/mecanicos?usuario=${this.user.usuario}`), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                });

                if (r.status === 404) {
                    throw new Error('Mec not found');
                }

                if (!r.ok) {
                    throw new Error(r.statusText);
                }

                const response = await r.json();

                this.userMec = response.data[0] as Mec;
            } catch (error: any) {
                this.error = error.message;
            }
        },

        async openSearchClienteModal() {
            if (this.cliente !== '') {
                this.currentCliente = this.cliente;
                await this.searchCliente();
            }
            this.modalSearchCliente?.show();
        },

        resetValues() {
            this.pageInfo = '';
            this.clientes = [];
            this.clienteMetaData = null;
            this.hasSearched = false;
            this.loadingClientes = false;
        },

        async createWorkOrder() {
            try {
                this.submitting = true;
                if (!this.selectedCliente) {
                    throw new Error('Cliente no encontrado');
                }
                const r = await fetch(url('/isiWeb/web/v1/empresas/01/ordenes-reparacion'), {
                    credentials: 'include',
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        ...this.newWorkOrder,
                        fedoc: this.fecdoc,
                        cif: this.selectedCliente.cif,
                        cli: this.selectedCliente.cli,
                        dir: this.selectedCliente.dir,
                        email: this.selectedCliente.email,
                        mec: this.userMec.mec,
                    } as WorkOrder),
                });

                if (!r.ok) {
                    const response = await r.json();
                    throw new Error(response.message);
                }
                const response = await r.json();
                this.submitting = false;
                this.$router.navigate(`/or/${response.data.OR}/details`);
                this.$dispatch(TOAST_TRIGGER, {
                    msg: `Orden de reparación ${response.data.OR} creada correctamente`,
                    level: 'success',
                });
            } catch (error: any) {
                console.error(error);
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
                this.submitting = false;
            }
        },

        selectCliente(cliente: Cliente) {
            this.selectedCliente = cliente;
        },

        setFormCliente() {
            if (this.selectedCliente !== null) {
                this.cliente = this.selectedCliente.cli.toString();
                this.workOrderCliente = this.selectedCliente;
                this.modalSearchCliente?.hide();
            }
        },

        async searchCliente() {
            const filter = this.buildFilter();

            try {
                if (filter !== '') {
                    this.loadingClientes = true;
                    const r = await fetch(url(`/isiWeb/web/v1/empresas/01/clientes?${filter}`), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        method: 'GET',
                    });

                    if (!r.ok) {
                        const response = await r.json();
                        throw new Error(response.message);
                    }
                    const response = await r.json();

                    this.clientes = response.data.slice(0, 15) as Cliente[];
                    this.clienteMetaData = response.meta as ClienteMetaData;

                    const startEntry = (this.currentPage - 1) * 15 + 1;
                    const endEntry = Math.min(this.currentPage * 15, this.clienteMetaData.rows);
                    this.pageInfo = `Mostrando ${startEntry} a ${endEntry} de ${this.clienteMetaData.rows} registros`;
                    this.loadingClientes = false;
                }
            } catch (error: any) {
                console.error(error);
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
        },

        async buildCliente(e: Event) {
            const cliente = (e.target as HTMLInputElement).value;

            try {
                this.workOrderCliente = null;
                if (cliente !== '') {
                    this.loadingClientes = true;
                    const r = await fetch(url(`/isiWeb/web/v1/empresas/01/clientes/${cliente}`), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        method: 'GET',
                    });

                    if (!r.ok) {
                        const response = await r.json();
                        if (this.selectedCliente) {
                            this.selectedCliente = null;
                        }
                        throw new Error(response.message);
                    }
                    const response = await r.json();

                    this.selectedCliente = response.data as Cliente;
                    this.workOrderCliente = this.selectedCliente;
                    this.clienteMetaData = response.meta as ClienteMetaData;
                    this.loadingClientes = false;
                }
            } catch (error: any) {
                console.error(error);
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
                this.loadingClientes = false;
                this.modalSearchCliente?.show();
                this.$refs.searchClienteInput?.focus();
            }
        },

        buildFilter(): string {
            let filter = '';

            filter = this.appendFilter(filter, this.currentCliente, 'cli', 1);
            filter = this.appendFilter(filter, this.currentRaz, 'raz', MIN_SEARCH_LENGTH);
            filter = this.appendFilter(filter, this.currentNom, 'nom', MIN_SEARCH_LENGTH);
            filter = this.appendFilter(filter, this.currentCif, 'cif', MIN_SEARCH_LENGTH);
            filter = this.appendFilter(filter, this.currentDir, 'dir', MIN_SEARCH_LENGTH);

            return filter;
        },

        appendFilter(existingFilter: string, value: string, key: string, minLength: number): string {
            let filter = existingFilter;
            if (value.length >= minLength) {
                if (filter !== '') {
                    filter += key === 'cli' ? `&${key}:=${value}` : `&${key}:like=${value}`;
                } else {
                    filter += key === 'cli' ? `${key}:=${value}` : `${key}:like=${value}`;
                }
            }
            return filter;
        },
    }),
} as ComponentModule;
